import{c as a,Q as n,j as t,m as p}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"网络学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"networkLearning/01-网络学习路线总览.md","filePath":"networkLearning/01-网络学习路线总览.md","lastUpdated":1778496697000}'),e={name:"networkLearning/01-网络学习路线总览.md"};function o(l,s,r,i,d,c){return n(),t("div",null,[...s[0]||(s[0]=[p(`<h1 id="网络学习路线总览" tabindex="-1">网络学习路线总览 <a class="header-anchor" href="#网络学习路线总览" aria-label="Permalink to &quot;网络学习路线总览&quot;">​</a></h1><p>webLearning 浅讲网络、backendLearning 第 55 章把 TCP/TLS/HTTP 粗扫一遍——但<strong>真要深挖到 RFC 级</strong>,做网关、做中间件、扛 DDoS、调 P99,就得开一个独立系列。</p><p>这套教程的定位是&quot;<strong>进阶补课</strong>&quot;:假设你会用 HTTP API、能写后端服务,但 <strong>不一定懂包怎么走、TCP 握手怎么实现、TLS 1.3 凭什么 1 RTT、QUIC 解决了什么、eBPF 能干什么</strong>。40 章把这些一次讲透。</p><hr><h2 id="一、为什么要-重新学一次网络" tabindex="-1">一、为什么要&quot;重新学一次网络&quot; <a class="header-anchor" href="#一、为什么要-重新学一次网络" aria-label="Permalink to &quot;一、为什么要&quot;重新学一次网络&quot;&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日常开发:</span></span>
<span class="line"><span>  fetch(&#39;https://api.example.com/orders&#39;)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>  ── 这一行后面发生了什么?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>90% 的人答得出&quot;DNS 解析、TCP 握手、TLS 握手、HTTP 请求&quot;</span></span>
<span class="line"><span>但答不出:</span></span>
<span class="line"><span>  ✗ DNS 走 UDP 还是 TCP?递归解析每一跳怎么找上游?</span></span>
<span class="line"><span>  ✗ TCP 握手第一个 SYN 包到底有几字节?</span></span>
<span class="line"><span>  ✗ TLS 1.3 ClientHello 里 KeyShare 是怎么&quot;猜算法&quot;的?</span></span>
<span class="line"><span>  ✗ HTTP/2 的 stream 优先级在 Linux 内核哪一层处理?</span></span>
<span class="line"><span>  ✗ 同一个 TLS 连接复用,Session Ticket 和 PSK 区别?</span></span></code></pre></div><p>这些&quot;会一点但说不清&quot;的灰色地带,是性能瓶颈、诡异 bug、面试被卡的真正现场。</p><blockquote><p>经验法则:<strong>网络是后端工程师天花板的最后一公里</strong>——业务代码 / 框架 / 算法都能学,网络这一层不下狠功夫永远摸不到。</p></blockquote><hr><h2 id="二、四层模型-vs-七层模型-别迷信-osi" tabindex="-1">二、四层模型 vs 七层模型:别迷信 OSI <a class="header-anchor" href="#二、四层模型-vs-七层模型-别迷信-osi" aria-label="Permalink to &quot;二、四层模型 vs 七层模型:别迷信 OSI&quot;">​</a></h2><p>教科书讲 OSI 七层:<strong>物理 / 数据链路 / 网络 / 传输 / 会话 / 表示 / 应用</strong>。<strong>实际工程中,99% 的协议按 TCP/IP 四层就够</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用层  HTTP / DNS / SMTP / SSH / WebSocket / gRPC</span></span>
<span class="line"><span>        ─────────────────────</span></span>
<span class="line"><span>传输层  TCP / UDP / QUIC / SCTP</span></span>
<span class="line"><span>        ─────────────────────</span></span>
<span class="line"><span>网络层  IP(v4 / v6) / ICMP / IGMP</span></span>
<span class="line"><span>        ─────────────────────</span></span>
<span class="line"><span>链路层  Ethernet / WiFi / PPP / VLAN</span></span>
<span class="line"><span>        ─────────────────────</span></span>
<span class="line"><span>物理层  铜缆 / 光纤 / 无线电波</span></span></code></pre></div><p><strong>会话层 / 表示层</strong> 在 TCP/IP 里被合到应用层——TLS 既不是会话层也不是表示层,<strong>实际上是&quot;夹在传输和应用之间的第 4.5 层&quot;</strong>,不要套 OSI。</p><blockquote><p>经验法则:<strong>面试问&quot;OSI 七层&quot;礼貌答完,工程讨论按 TCP/IP 四层 + TLS 中间层</strong>——清晰、对得上代码。</p></blockquote><hr><h2 id="三、本系列内容地图" tabindex="-1">三、本系列内容地图 <a class="header-anchor" href="#三、本系列内容地图" aria-label="Permalink to &quot;三、本系列内容地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    [01-05] 基础与心智模型</span></span>
<span class="line"><span>                            ↓</span></span>
<span class="line"><span>       ┌────────────────────────────────────────┐</span></span>
<span class="line"><span>       ▼                                        ▼</span></span>
<span class="line"><span>  [06-10] IP / 路由 / ICMP                [27-29] DNS 体系</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  [11-16] 传输层(UDP / TCP / 拥塞 / MPTCP)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  [17-21] TLS 与密码学(1.2/1.3/mTLS/PKI)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  [22-26] HTTP 演进(1.1/2/3/QUIC/WebSocket/WebRTC)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>       ┌────────────────────────────────────────┐</span></span>
<span class="line"><span>       ▼                                        ▼</span></span>
<span class="line"><span>  [30-33] Linux 内核网络             [34-36] 反向代理 / LB / CDN</span></span>
<span class="line"><span>   socket / epoll / io_uring / eBPF / DPDK</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  [37-38] 安全与防御(WAF / DDoS / 渗透)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>  [39-40] 抓包高级 + 压测 + 排障方法论</span></span></code></pre></div><p>40 章的产出目标:<strong>任何一种网络问题,你能定位到&quot;是哪一层、哪个协议、哪个具体环节&quot;</strong>——不再是&quot;抖动了&quot;&quot;慢了&quot;&quot;不通&quot;这种模糊报告。</p><hr><h2 id="四、技术栈与工具栈" tabindex="-1">四、技术栈与工具栈 <a class="header-anchor" href="#四、技术栈与工具栈" aria-label="Permalink to &quot;四、技术栈与工具栈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>工具</th></tr></thead><tbody><tr><td><strong>抓包</strong></td><td>tcpdump / Wireshark / tshark / mitmproxy</td></tr><tr><td><strong>测试客户端</strong></td><td>curl / openssl s_client / nghttp / quiche-client</td></tr><tr><td><strong>DNS</strong></td><td>dig / drill / nslookup / dog</td></tr><tr><td><strong>路由 / ICMP</strong></td><td>ping / traceroute / mtr / tracepath</td></tr><tr><td><strong>socket / 网络栈</strong></td><td>ss / netstat / lsof / strace</td></tr><tr><td><strong>性能 / 压测</strong></td><td>iperf3 / netperf / wrk / h2load</td></tr><tr><td><strong>eBPF</strong></td><td>bcc / bpftrace / cilium</td></tr><tr><td><strong>TLS 调试</strong></td><td>testssl.sh / sslscan / ssllabs</td></tr><tr><td><strong>代理 / LB</strong></td><td>Nginx / Envoy / HAProxy</td></tr><tr><td><strong>可视化</strong></td><td>Wireshark I/O 图、Grafana 网络看板</td></tr></tbody></table><blockquote><p>经验法则:<strong>网络工程师的&quot;必装&quot;是 tcpdump + Wireshark + dig + curl + openssl + ss + mtr</strong> 这七件套——任何一台 Linux 上手就能调试,缺一个少一根肋骨。</p></blockquote><hr><h2 id="五、网络心智的三个核心模型" tabindex="-1">五、网络心智的三个核心模型 <a class="header-anchor" href="#五、网络心智的三个核心模型" aria-label="Permalink to &quot;五、网络心智的三个核心模型&quot;">​</a></h2><h3 id="_1-包-的视角" tabindex="-1">1. &quot;包&quot;的视角 <a class="header-anchor" href="#_1-包-的视角" aria-label="Permalink to &quot;1. &quot;包&quot;的视角&quot;">​</a></h3><p>万物皆包。一次 HTTP 请求是几十个 IP 包(SYN / SYN+ACK / ACK / ClientHello / ...)的有序组合。<strong>会看包,网络才算入门</strong>。</p><h3 id="_2-时序-的视角" tabindex="-1">2. &quot;时序&quot;的视角 <a class="header-anchor" href="#_2-时序-的视角" aria-label="Permalink to &quot;2. &quot;时序&quot;的视角&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T0 ─── DNS 查询 ───┐</span></span>
<span class="line"><span>                    ├── DNS 解析(50ms)</span></span>
<span class="line"><span>T0 + 50ms ──────── ┘</span></span>
<span class="line"><span>                   ┌── TCP 三次握手(1 RTT)</span></span>
<span class="line"><span>T0 + 100ms ──────  │</span></span>
<span class="line"><span>                   ├── TLS 握手(1 RTT 复用 / 2 RTT 全握)</span></span>
<span class="line"><span>T0 + 200ms ──────  │</span></span>
<span class="line"><span>                   ├── HTTP 请求 + 响应(0.5 RTT 内可能多包)</span></span>
<span class="line"><span>T0 + 250ms ──────  ┘</span></span></code></pre></div><p><strong>性能问题永远是某段时序里的瓶颈</strong>。不会画时序图,优化就是瞎拍。</p><h3 id="_3-状态机-的视角" tabindex="-1">3. &quot;状态机&quot;的视角 <a class="header-anchor" href="#_3-状态机-的视角" aria-label="Permalink to &quot;3. &quot;状态机&quot;的视角&quot;">​</a></h3><p>TCP / TLS / HTTP/2 / QUIC 都是<strong>复杂状态机</strong>。出 bug 时往往是&quot;状态没切对&quot;:TIME_WAIT 没退、TLS Client/Server 状态错位、QUIC 连接迁移没生效。</p><blockquote><p>经验法则:<strong>学网络协议永远先画状态机</strong>——三次握手、四次挥手、TLS 握手、HTTP/2 stream 状态——画一遍就懂了一半。</p></blockquote><hr><h2 id="六、和已有系列的衔接" tabindex="-1">六、和已有系列的衔接 <a class="header-anchor" href="#六、和已有系列的衔接" aria-label="Permalink to &quot;六、和已有系列的衔接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>已有系列</th><th>重叠点</th><th>本系列怎么深挖</th></tr></thead><tbody><tr><td>webLearning(浅讲网络)</td><td>HTTP 状态码、Cookie</td><td>帧 / 头压缩 / 优先级 / 多路复用</td></tr><tr><td>backendLearning ch.55</td><td>TCP/TLS/HTTP 调优</td><td>同样话题但展开到 RFC 细节 + Linux 内核</td></tr><tr><td>backendLearning ch.32/60(微服务/Mesh)</td><td>mTLS / 服务发现</td><td>数据面 Envoy 内部 / SPIFFE / eBPF</td></tr><tr><td>backendLearning ch.45(对象存储)</td><td>CDN</td><td>调度算法 / 边缘缓存策略</td></tr></tbody></table><blockquote><p>经验法则:<strong>重复不可怕,重复带新视角才是好教学</strong>。Backend 55 章告诉你&quot;开 BBR&quot;;本系列告诉你&quot;BBR 怎么建模带宽 / 跟 CUBIC 怎么混跑 / 怎么调 cwnd 上限&quot;。</p></blockquote><hr><h2 id="七、阅读姿势" tabindex="-1">七、阅读姿势 <a class="header-anchor" href="#七、阅读姿势" aria-label="Permalink to &quot;七、阅读姿势&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 边读边抓包</span></span>
<span class="line"><span>   每讲一个协议,自己抓一次包对照</span></span>
<span class="line"><span>   tcpdump -i any -w t.pcap port 80</span></span>
<span class="line"><span>   open t.pcap (Wireshark)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 读 RFC 节选</span></span>
<span class="line"><span>   每章末尾给关键 RFC 链接,挑一两节看</span></span>
<span class="line"><span>   面试时引用 RFC 编号瞬间专业感拉满</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 配合实验</span></span>
<span class="line"><span>   起一个 Nginx,改 SSL 配置,curl 看效果</span></span>
<span class="line"><span>   起一个 Quiche / nghttp,看 HTTP/3</span></span>
<span class="line"><span>   抓自己的真实流量观察</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 查表式回看</span></span>
<span class="line"><span>   常见踩坑、Checklist 这种结构化内容反复翻</span></span>
<span class="line"><span>   出问题时按图索骥,而非从头翻</span></span></code></pre></div><hr><h2 id="八、容易踩的-伪深度-陷阱" tabindex="-1">八、容易踩的&quot;伪深度&quot;陷阱 <a class="header-anchor" href="#八、容易踩的-伪深度-陷阱" aria-label="Permalink to &quot;八、容易踩的&quot;伪深度&quot;陷阱&quot;">​</a></h2><p>很多人学网络停在&quot;知道名词&quot;:</p><table tabindex="0"><thead><tr><th>伪深度</th><th>真深度</th></tr></thead><tbody><tr><td>&quot;TCP 握手是三次&quot;</td><td>&quot;三次的根本原因是消息可能丢,两次握不出双向确认&quot;</td></tr><tr><td>&quot;HTTP/2 多路复用&quot;</td><td>&quot;stream 0 是控制流;HEADERS 帧前必须有 PRIORITY 帧?HPACK 怎么避免 CRIME 攻击&quot;</td></tr><tr><td>&quot;TLS 1.3 比 1.2 快&quot;</td><td>&quot;把 ServerKeyExchange 合进 ServerHello,且禁掉了 RSA 密钥交换&quot;</td></tr><tr><td>&quot;BBR 比 CUBIC 好&quot;</td><td>&quot;BBR 在共享瓶颈链路下与 CUBIC 不公平,大流量场景挤掉对手&quot;</td></tr></tbody></table><p><strong>判断自己是否真懂</strong>:能不能给一个新人讲到他能复述。</p><hr><h2 id="九、本章-checklist" tabindex="-1">九、本章 Checklist <a class="header-anchor" href="#九、本章-checklist" aria-label="Permalink to &quot;九、本章 Checklist&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>说明</th></tr></thead><tbody><tr><td>✅ TCP/IP 四层模型(非 OSI 七层)</td><td>工程视角</td></tr><tr><td>✅ 装好 tcpdump + Wireshark + dig + curl + openssl + ss + mtr</td><td>调试七件套</td></tr><tr><td>✅ 任意 HTTPS 请求能画&quot;DNS+TCP+TLS+HTTP&quot;时序</td><td>心智基础</td></tr><tr><td>✅ 知道 TCP 状态机至少 11 种状态</td><td>必修</td></tr><tr><td>✅ 装一份本地 Nginx,边读边抓包</td><td>实践基础</td></tr><tr><td>✅ RFC 编号能脱口而出几个(7540 / 8446 / 9000)</td><td>行家信号</td></tr></tbody></table><hr><h2 id="十、小结" tabindex="-1">十、小结 <a class="header-anchor" href="#十、小结" aria-label="Permalink to &quot;十、小结&quot;">​</a></h2><p>网络这门学科最反直觉的地方是:<strong>它跨度大但没有&quot;主线&quot;</strong>——TCP 跟 DNS 没继承关系、HTTP/3 跟 HTTP/2 思路相反、TLS 是&quot;插在协议栈中间的怪物&quot;。<strong>只能一段一段啃</strong>。</p><p>记住三件事:</p><ol><li><strong>会抓包是入门门票</strong>——不会抓包,网络永远是&quot;黑盒&quot;</li><li><strong>协议演进往往是&quot;修复上一代的根本缺陷&quot;</strong>——HTTP/2 修 1.1 的队头阻塞、HTTP/3 又修 HTTP/2 的 TCP 队头阻塞</li><li><strong>任何&quot;魔法般快&quot;的优化都源于减少 RTT</strong>——这是网络优化的最大杠杆</li></ol><p>下一章我们从&quot;一个 HTTP 请求被发出去后,到底变成了几个包,每个包哪些字段&quot;开始——<strong>协议栈与封装</strong>。</p>`,53)])])}const g=a(e,[["render",o]]);export{u as __pageData,g as default};
